<span class="line"><span style="color:#FD971F;">            self</span><span style="color:#F8F8F2;">.head </span><span style="color:#F92672;">=</span><span style="color:#FD971F;"> self</span><span style="color:#F8F8F2;">.tail </span><span style="color:#F92672;">=</span><span style="color:#AE81FF;"> None</span></span>
