<span class="line"><span style="color:#F92672;">            while</span><span style="color:#F8F8F2;"> current.next.next </span><span style="color:#F92672;">is</span><span style="color:#F92672;"> not</span><span style="color:#AE81FF;"> None</span><span style="color:#F8F8F2;">:  </span><span style="color:#88846F;"># 查找倒数第二个节点</span></span>
